script:
frappe.ui.form.on("Student Certificate", {
    before_save(frm) {

        if (!frm.doc.generated_on) {
            frm.set_value("generated_on", frappe.datetime.now_datetime());
        }

        if (!frm.doc.generated_by) {
            frm.set_value("generated_by", frappe.session.user);
        }

    }
});
